const body = $input.first().json.body;
if (!body || !body.entry) return [{ json: { skip: true } }];

const results = [];
for (const entry of body.entry) {
  for (const msg of (entry.messaging || [])) {
    if (!msg.message) continue;
    const isImage = msg.message.attachments?.some(a => a.type === 'image');
    results.push({
      json: {
        skip: false,
        sender_id: msg.sender.id,
        platform: body.object === 'instagram' ? 'instagram' : 'facebook',
        is_image: isImage || false,
        text: msg.message.text || '',
        image_url: isImage ? msg.message.attachments[0].payload.url : null,
        timestamp: msg.timestamp
      }
    });
  }
}
return results.length ? results : [{ json: { skip: true } }];

