const raw = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let result = {};
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  result = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch(e) { result = { confidence: 'low' }; }

const prev = $('Parse Meta Event').first().json;
return [{ json: {
  ...prev,
  vision_result: result,
  text: result.confidence === 'low'
    ? '__LOW_CONFIDENCE__'
    : `สนใจ ${result.matched_name}`,
  matched_sku: result.matched_sku || ''
}}];

