const raw = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || 'ขออภัยค่ะ ลองใหม่อีกครั้งนะคะ';
const meta = $('รูปภาพหรือข้อความ?').first().json;

let action = 'reply';
let orderData = null;
let replyText = raw;

if (raw.trim() === '__ESCALATE__') {
  action = 'escalate';
  replyText = '🙏 กำลังโอนสายให้แอดมินเลยค่ะ รอสักครู่นะคะ 💕';
} else if (raw.includes('__ORDER__:')) {
  action = 'create_order';
  try {
    const jsonPart = raw.split('__ORDER__:')[1].trim();
    orderData = JSON.parse(jsonPart);
  } catch(e) { action = 'reply'; }
  replyText = orderData
    ? `✅ รับออเดอร์แล้วนะคะ!\n📦 ${orderData.sku} ไซต์ ${orderData.size} สี ${orderData.color} × ${orderData.qty}\nรอแอดมินยืนยันและแจ้งยอดรวมค่าส่งให้นะคะ 💕`
    : raw;
} else if (raw === '__LOW_CONFIDENCE__') {
  replyText = 'ขอโทษนะคะ ขอรูปที่ชัดขึ้นได้มั้ยคะ? หรือพิมพ์ชื่อสินค้าที่ต้องการได้เลยค่ะ 📸';
}

return [{ json: {
  sender_id: meta.sender_id,
  platform: meta.platform,
  action,
  reply: replyText,
  order_data: orderData
}}];

